actions.customAction:
const recapDiv = document.getElementById("recapDisplay");
let list_of_datagrid = [];
let data_stock = [];
const exclude = ["button", "file", "container", "panel", "datagrid", "hidden"];
const excludeKeys = ["luEtApprouve", "motifAgent", "numeroDossier", "nbCorrections"];
const includesLabelForSelect = ["libelle", "label"];

utils.eachComponent(form.components, (component, path) => {
  let splitted_path = path.split(".");
  let skip = false;
  if (
    !exclude.includes(component.type) &&
    !excludeKeys.includes(component.key) &&
    !component.hidden &&
    ![null, undefined, "", [], {}].includes(data[component.key]) &&
    !(typeof data[component.key] === "string" && ["", "null", "undefined"].includes(data[component.key]))
  ) {
    if (component.type === "datagrid") {
      list_of_datagrid.push(component.key);
    } else {
      if (splitted_path.length >= 2 && list_of_datagrid.includes(splitted_path[splitted_path.length - 2])) {
        skip = true;
      }
    }
    if (!skip) {
      data_stock.push({ key: component.key, label: component.label, value: data[component.key] || (component.type === "datagrid" ? [] : ""), type: component.type, components: component.components || "" });
    }
  }
}, false);

let ourTable = `<style>.recap-container{width:100%;margin:0 auto;}.recap-table{width:100%;border-collapse:collapse;}.recap-table thead th{background-color:#F8F9FA;color:#212529;font-weight:700;padding:12px;border:1px solid #DEE2E6;text-align:left;font-family:-apple-system,system-ui,sans-serif;font-size:15px;}.recap-table th,.recap-table td{border:1px solid #DEE2E6;padding:12px;text-align:left;font-size:14px;font-family:-apple-system,system-ui,sans-serif;}.recap-table td:first-child{width:6%;text-align:center;color:#6C757D;}.recap-table td:nth-child(2){width:44%;font-weight:600;color:#212529;}.recap-table td:last-child{width:50%;color:#495057;}</style><div class="recap-container"><table class="recap-table"><thead><tr><th>N°</th><th>Donnée</th><th>Votre saisie</th></tr></thead><tbody>`;

let index = 1;
data_stock.forEach((elmt) => {
  let finalVal = elmt.value;
  if (elmt.type === "datetime") finalVal = new Date(elmt.value).toLocaleDateString('fr-TG');
  ourTable += `<tr><td>${index++}</td><td>${elmt.label}</td><td><b>${finalVal}</b></td></tr>`;
});

ourTable += `</tbody></table></div>`;
recapDiv.innerHTML = ourTable;
